import{_ as s,c as e,o as a,a1 as o}from"./chunks/framework.DDNAyvCW.js";const i="/assets/MCP.CttIsW7S.png",d="/assets/add-mcp-server.ZT8Oh_Ip.gif",l="/assets/toggle-tools.DUrVpNU1.gif",n="/assets/auto-approve.BVy5g89q.png",r="/assets/tools-resources.vyXpns-O.png",q=JSON.parse('{"title":"MCP 使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mcp/usage/index.md","filePath":"docs/mcp/usage/index.md"}'),c={name:"docs/mcp/usage/index.md"};function p(h,t,u,k,g,m){return a(),e("div",null,t[0]||(t[0]=[o('<h1 id="mcp-使用指南" tabindex="-1">MCP 使用指南 <a class="header-anchor" href="#mcp-使用指南" aria-label="Permalink to &quot;MCP 使用指南&quot;">​</a></h1><p>MCP（Model Context Protocol）允许你通过连接 MCP 服务器，为 Chaterm 的 AI 扩展外部工具、知识库和 API 能力。</p><p><img src="'+i+'" alt=""></p><h2 id="你的第一个-mcp-服务器" tabindex="-1">你的第一个 MCP 服务器 <a class="header-anchor" href="#你的第一个-mcp-服务器" aria-label="Permalink to &quot;你的第一个 MCP 服务器&quot;">​</a></h2><p>五分钟内即可完成配置。</p><ol><li>在 Chaterm 中打开<strong>设置</strong>。</li><li>进入<strong>工具与 MCP</strong> 标签页，点击<strong>添加服务器</strong> —— 系统会自动打开 <code>mcp_setting.json</code> 文件。</li><li>将下面的 JSON 示例粘贴到编辑器中。</li><li>保存文件。Chaterm 会自动连接该服务器。</li></ol><p>保存后，服务器的状态徽标会从 <em>connecting</em> 变为 <em>connected</em>（或显示错误信息），工具（Tools）和资源（Resources）会自动加载。</p><p><img src="'+d+`" alt=""></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>不确定先试哪个服务器？下方的 <strong>filesystem</strong> 服务器是一个很好的起点 —— 它可以让 AI 对你指定的目录进行读写访问。</p></div><hr><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><h3 id="stdio-服务器-本地命令行" tabindex="-1">STDIO 服务器（本地命令行） <a class="header-anchor" href="#stdio-服务器-本地命令行" aria-label="Permalink to &quot;STDIO 服务器（本地命令行）&quot;">​</a></h3><p>当 MCP 服务器以本地进程方式运行时，使用此类型。</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// MCP server using stdio transport</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;@modelcontextprotocol/server-filesystem&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;/Users/username/Desktop&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &quot;/path/to/other/allowed/dir&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="stdio-配置字段" tabindex="-1">STDIO 配置字段 <a class="header-anchor" href="#stdio-配置字段" aria-label="Permalink to &quot;STDIO 配置字段&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>必需</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>type</code></td><td>否</td><td>连接类型，省略时会根据 <code>command</code> 推断为 <code>stdio</code></td><td><code>&quot;stdio&quot;</code></td></tr><tr><td><code>command</code></td><td>是</td><td>启动可执行命令。可写为完整一行（含参数），或仅可执行名</td><td><code>&quot;npx&quot;</code>、<code>&quot;node&quot;</code>、<code>&quot;python&quot;</code></td></tr><tr><td><code>args</code></td><td>否</td><td>传递给命令的参数数组；当 <code>command</code> 含空格且未提供 <code>args</code> 时，系统会自动解析（支持引号与转义）</td><td><code>[&quot;-y&quot;, &quot;@modelcontextprotocol/server-filesystem&quot;]</code></td></tr><tr><td><code>cwd</code></td><td>否</td><td>进程工作目录</td><td><code>&quot;/Users/you&quot;</code></td></tr><tr><td><code>env</code></td><td>否</td><td>进程环境变量（键值对）</td><td><code>{&quot;API_KEY&quot;: &quot;xxx&quot;}</code></td></tr><tr><td><code>disabled</code></td><td>否</td><td>是否禁用该服务器</td><td><code>true</code>/<code>false</code></td></tr><tr><td><code>timeout</code></td><td>否</td><td>调用超时时间（秒）</td><td><code>120</code>、<code>180</code></td></tr><tr><td><code>autoApprove</code></td><td>否</td><td>自动批准工具白名单（按工具名）</td><td><code>[&quot;read_file&quot;]</code></td></tr></tbody></table><p>说明：</p><ul><li>不支持 <code>envFile</code> 字段；若需从文件加载变量，请在启动环境中自行处理后再写入 <code>env</code>。</li><li>兼容字段：为向后兼容，<code>url?</code>、<code>headers?</code> 在 stdio 配置里也被允许，但不建议使用（不会将连接类型切换为 http）。</li></ul><h3 id="http-服务器-远程服务" tabindex="-1">HTTP 服务器（远程服务） <a class="header-anchor" href="#http-服务器-远程服务" aria-label="Permalink to &quot;HTTP 服务器（远程服务）&quot;">​</a></h3><p>当 MCP 服务器部署在远端并暴露 Streamable HTTP 端点时，使用此类型。</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;context7&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;url&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://mcp.context7.com/mcp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;headers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;CONTEXT7_API_KEY&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-api-key&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="http-配置字段" tabindex="-1">HTTP 配置字段 <a class="header-anchor" href="#http-配置字段" aria-label="Permalink to &quot;HTTP 配置字段&quot;">​</a></h4><table tabindex="0"><thead><tr><th>字段</th><th>必需</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>type</code></td><td>否</td><td>连接类型，省略时会根据 <code>url</code> 推断为 <code>http</code></td><td><code>&quot;http&quot;</code></td></tr><tr><td><code>url</code></td><td>是</td><td>服务器地址（支持流式 HTTP 客户端）</td><td><code>&quot;https://your-mcp-host.example.com/&quot;</code></td></tr><tr><td><code>headers</code></td><td>否</td><td>请求头（如认证、代理相关）</td><td><code>{&quot;Authorization&quot;: &quot;Bearer &lt;TOKEN&gt;&quot;}</code></td></tr><tr><td><code>disabled</code></td><td>否</td><td>是否禁用该服务器</td><td><code>true</code>/<code>false</code></td></tr><tr><td><code>timeout</code></td><td>否</td><td>调用超时时间（秒）</td><td><code>120</code>、<code>180</code></td></tr><tr><td><code>autoApprove</code></td><td>否</td><td>自动批准工具白名单（按工具名）</td><td><code>[&quot;search&quot;]</code></td></tr></tbody></table><p>说明：</p><ul><li><code>url</code> 必须是合法的 URL（由 schema 强校验）。</li><li>兼容字段：为向后兼容，<code>command?</code>、<code>args?</code>、<code>env?</code> 在 http 配置里也被允许，仅用于旧配置迁移场景；不建议长期使用。</li></ul><h3 id="通用字段" tabindex="-1">通用字段 <a class="header-anchor" href="#通用字段" aria-label="Permalink to &quot;通用字段&quot;">​</a></h3><blockquote><p>参考项目中的 <code>schemas.ts</code>：</p><ul><li>通用字段（两类都支持）：<code>disabled?</code>、<code>timeout?</code>（秒，默认值见应用）、<code>autoApprove?</code>（字符串数组）。</li><li><code>type</code> 可选：当提供了 <code>command</code>（推断为 stdio）或 <code>url</code>（推断为 http）时可省略；推荐显式填写以提高可读性。</li><li>兼容字段：支持 legacy <code>transportType</code>，应用会自动转换为 <code>type</code>；不建议在新配置中继续使用。</li></ul></blockquote><hr><h2 id="在对话中使用-mcp" tabindex="-1">在对话中使用 MCP <a class="header-anchor" href="#在对话中使用-mcp" aria-label="Permalink to &quot;在对话中使用 MCP&quot;">​</a></h2><h3 id="工具开关" tabindex="-1">工具开关 <a class="header-anchor" href="#工具开关" aria-label="Permalink to &quot;工具开关&quot;">​</a></h3><p>在<strong>工具</strong>列表中点击工具名称即可启用或禁用该工具。已禁用的工具会从模型上下文中完全移除，Agent 无法再使用该工具。关闭不需要使用的工具是节省 token 的简单方法。</p><p><img src="`+l+'" alt=""></p><h3 id="自动批准" tabindex="-1">自动批准 <a class="header-anchor" href="#自动批准" aria-label="Permalink to &quot;自动批准&quot;">​</a></h3><p>在配置中将工具名加入 <code>autoApprove</code> 后，匹配的工具将跳过确认步骤直接执行。你也可以在对话过程中动态将工具添加到自动批准列表。</p><p><img src="'+n+'" alt=""></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>仅将你完全信任的工具添加到 <code>autoApprove</code>。自动批准的工具会跳过确认对话框，无需用户审核即可执行。</p></div><h3 id="查看参数和资源" tabindex="-1">查看参数和资源 <a class="header-anchor" href="#查看参数和资源" aria-label="Permalink to &quot;查看参数和资源&quot;">​</a></h3><p>展开工具的 <strong>PARAMETERS</strong> 折叠面板可查看参数名、是否必填及描述。</p><p>在 <strong>Resources</strong> 标签页中可以查看资源名称、描述和 URI；在支持的入口中可直接读取资源。</p><p><img src="'+r+'" alt=""></p><hr><h2 id="开发提示" tabindex="-1">开发提示 <a class="header-anchor" href="#开发提示" aria-label="Permalink to &quot;开发提示&quot;">​</a></h2><h3 id="文件变更自动重启" tabindex="-1">文件变更自动重启 <a class="header-anchor" href="#文件变更自动重启" aria-label="Permalink to &quot;文件变更自动重启&quot;">​</a></h3><p>如果你以构建产物运行本地 MCP 服务器（例如 <code>build/index.js</code>），Chaterm 会检测该文件的变更并自动重启对应的 stdio 服务器。这能显著加快开发迭代速度。</p><p>若自动重启未触发，可通过<strong>禁用然后启用</strong>该服务器来手动重连。</p><hr><h2 id="去哪里找-mcp-服务器" tabindex="-1">去哪里找 MCP 服务器 <a class="header-anchor" href="#去哪里找-mcp-服务器" aria-label="Permalink to &quot;去哪里找 MCP 服务器&quot;">​</a></h2><ul><li><strong>GitHub 仓库</strong>： <ul><li><a href="https://github.com/modelcontextprotocol/servers" target="_blank" rel="noreferrer">modelcontextprotocol/servers</a></li><li><a href="https://github.com/punkpeye/awesome-mcp-servers" target="_blank" rel="noreferrer">punkpeye/awesome-mcp-servers</a></li></ul></li><li><strong>在线 MCP 目录</strong>： <ul><li><a href="https://mcpservers.org/" target="_blank" rel="noreferrer">mcpservers.org</a></li><li><a href="https://mcp.so/" target="_blank" rel="noreferrer">mcp.so</a></li><li><a href="https://glama.ai/mcp/servers" target="_blank" rel="noreferrer">glama.ai/mcp/servers</a></li></ul></li><li><strong>PulseMCP</strong>：<a href="https://www.pulsemcp.com/" target="_blank" rel="noreferrer">www.pulsemcp.com</a></li></ul><hr><h2 id="安全与性能建议" tabindex="-1">安全与性能建议 <a class="header-anchor" href="#安全与性能建议" aria-label="Permalink to &quot;安全与性能建议&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">安全检查清单</p><ul><li>仅将信任的工具添加到 <code>autoApprove</code>。</li><li>谨慎在 <code>env</code> 或 <code>headers</code> 中注入凭证 —— 避免分享包含敏感信息的配置文件。</li><li>遵循最小权限原则：仅暴露实际需要的目录、网络和 API。</li></ul></div><ul><li><strong>性能</strong>：一般网络情况下，将 <code>timeout</code> 设为 120 - 180 秒。对远端服务，优先选择就近端点，并确保代理不会中断流式连接。</li><li><strong>可维护性</strong>：使用统一的命名规范并将相关服务器分组管理。定期备份 <code>mcp_setting.json</code>。</li></ul><hr><h2 id="后续阅读" tabindex="-1">后续阅读 <a class="header-anchor" href="#后续阅读" aria-label="Permalink to &quot;后续阅读&quot;">​</a></h2><ul><li>遇到连接或调用问题？请参阅 <a href="./../troubleshooting/">MCP 故障排除与最佳实践</a>。</li></ul>',55)]))}const b=s(c,[["render",p]]);export{q as __pageData,b as default};
